$ErrorActionPreference = 'Stop'
$Root = (Get-Location).Path
$Utf8NoBom = New-Object System.Text.UTF8Encoding($false)
function Write-Utf8NoBom([string]$Path, [string]$Content) { $Dir = Split-Path -Parent $Path; if ($Dir) { New-Item -ItemType Directory -Force -Path $Dir | Out-Null }; [System.IO.File]::WriteAllText($Path, $Content, $Utf8NoBom) }
function Write-Base64File([string]$RelativePath, [string]$Data) { $Path = Join-Path $Root $RelativePath; $Dir = Split-Path -Parent $Path; New-Item -ItemType Directory -Force -Path $Dir | Out-Null; [System.IO.File]::WriteAllBytes($Path, [Convert]::FromBase64String($Data)) }
