function Patch-File([string]$RelativePath, [scriptblock]$Transform) {
    $Path = Join-Path $Root $RelativePath
    if (-not (Test-Path -LiteralPath $Path)) { throw "Missing required file: $RelativePath" }
    $Text = [System.IO.File]::ReadAllText($Path)
    $Updated = & $Transform $Text
    Write-Utf8NoBom $Path $Updated
}

Patch-File 'src/main/java/net/droingo/decor/registry/DecorBlocks.java' {
    param($t)
    if ($t -notmatch 'THE_BEAST_SKULL') {
        $t = $t.Replace('import net.droingo.decor.content.CeilingPlantBlock;', "import net.droingo.decor.content.CeilingPlantBlock;`r`nimport net.droingo.decor.content.BeastSkullBlock;")
        $marker = '    public static final DeferredBlock<CeilingPlantBlock> CEILING_PLANT ='
        $insert = @'
    public static final DeferredBlock<BeastSkullBlock> THE_BEAST_SKULL =
            BLOCKS.registerBlock(
                    "the_beast_skull",
                    BeastSkullBlock::new,
                    BlockBehaviour.Properties.of()
                            .mapColor(MapColor.COLOR_BROWN)
                            .strength(1.2F)
                            .sound(SoundType.BONE_BLOCK)
                            .noOcclusion()
                            .noCollission()
            );

'@
        $t = $t.Replace($marker, $insert + $marker)
    }
    return $t
}

Patch-File 'src/main/java/net/droingo/decor/registry/DecorItems.java' {
    param($t)
    if ($t -notmatch 'THE_BEAST_SKULL') {
        $t = $t.Replace('import net.droingo.decor.content.CeilingPlantItem;', "import net.droingo.decor.content.CeilingPlantItem;`r`nimport net.droingo.decor.content.BeastSkullItem;")
        $marker = '    public static final DeferredItem<Item> POTTED_PLANT_CEILING ='
        $insert = @'
    public static final DeferredItem<Item> THE_BEAST_SKULL =
            ITEMS.register(
                    "the_beast_skull",
                    () -> new BeastSkullItem(new Item.Properties().stacksTo(1))
            );

'@
        $t = $t.Replace($marker, $insert + $marker)
    }
    return $t
}

Patch-File 'src/main/java/net/droingo/decor/registry/DecorBlockEntities.java' {
    param($t)
    if ($t -notmatch 'BEAST_SKULL') {
        $t = $t.Replace('import net.droingo.decor.content.CeilingPlantBlockEntity;', "import net.droingo.decor.content.CeilingPlantBlockEntity;`r`nimport net.droingo.decor.content.BeastSkullBlockEntity;")
        $marker = '    public static final DeferredHolder<'
        $insert = @'
    public static final DeferredHolder<
            BlockEntityType<?>,
            BlockEntityType<BeastSkullBlockEntity>
            > BEAST_SKULL = TYPES.register(
            "the_beast_skull",
            () -> BlockEntityType.Builder.of(
                    BeastSkullBlockEntity::new,
                    DecorBlocks.THE_BEAST_SKULL.get()
            ).build(null)
    );

'@
        $idx = $t.IndexOf($marker)
        if ($idx -lt 0) { throw 'Could not find block entity registration insertion point.' }
        $t = $t.Insert($idx, $insert)
    }
    return $t
}

Patch-File 'src/main/java/net/droingo/decor/DroingosDecor.java' {
    param($t)
    if ($t -notmatch 'DecorEntities') {
        $t = $t.Replace('import net.droingo.decor.registry.DecorItems;', "import net.droingo.decor.registry.DecorItems;`r`nimport net.droingo.decor.registry.DecorEntities;")
        $t = $t.Replace('        DecorBlockEntities.register(modBus);', "        DecorBlockEntities.register(modBus);`r`n        DecorEntities.register(modBus);")
    }
    return $t
}

Patch-File 'src/main/java/net/droingo/decor/client/DroingosDecorClient.java' {
    param($t)
    if ($t -notmatch 'BeastSkullRenderer') {
        $t = $t.Replace('import net.droingo.decor.client.render.CeilingPlantRenderer;', "import net.droingo.decor.client.render.CeilingPlantRenderer;`r`nimport net.droingo.decor.client.render.BeastSkullRenderer;`r`nimport net.droingo.decor.client.render.BeastSkullSeatRenderer;")
        $t = $t.Replace('import net.droingo.decor.registry.DecorBlockEntities;', "import net.droingo.decor.registry.DecorBlockEntities;`r`nimport net.droingo.decor.registry.DecorEntities;")
        $marker = '        event.registerBlockEntityRenderer('
        $insert = @'
        event.registerBlockEntityRenderer(
                DecorBlockEntities.BEAST_SKULL.get(),
                BeastSkullRenderer::new
        );
        event.registerEntityRenderer(
                DecorEntities.BEAST_SKULL_SEAT.get(),
                BeastSkullSeatRenderer::new
        );

'@
        $idxRenderer = $t.IndexOf($marker, $t.IndexOf('registerBlockEntityRenderers'))
        if ($idxRenderer -lt 0) { throw 'Could not find client renderer insertion point.' }
        $t = $t.Insert($idxRenderer, $insert)
        $marker2 = '        event.register('
        $models = @'
        for (String modelName : java.util.List.of(
                "the_beast_floor_static",
                "the_beast_floor_jaw",
                "the_beast_wall_static",
                "the_beast_wall_jaw",
                "the_beast_ceiling_static",
                "the_beast_ceiling_jaw"
        )) {
            event.register(
                    ModelResourceLocation.standalone(
                            net.minecraft.resources.ResourceLocation.fromNamespaceAndPath(
                                    DroingosDecor.MOD_ID,
                                    "block/" + modelName
                            )
                    )
            );
        }

'@
        $idx = $t.IndexOf($marker2, $t.IndexOf('registerAdditionalModels'))
        if ($idx -ge 0) { $t = $t.Insert($idx, $models) }
    }
    return $t
}

Patch-File 'src/main/java/net/droingo/decor/registry/DecorDefinitionRegistry.java' {
    param($t)
    if ($t -notmatch 'ResourceLocation beastSkullId') {
        $marker = '        ResourceLocation parrotId = id("bobble_parrot");'
        $insert = @'
        ResourceLocation beastSkullId = id("the_beast_skull");
        register(
                DecorDefinition.builder(beastSkullId)
                        .category(DecorCategory.FURNITURE)
                        .placement(DecorPlacementType.LARGE)
                        .item(DecorItems.THE_BEAST_SKULL::get)
                        .bounds(-0.55D, 0.0D, -0.55D, 0.55D, 1.95D, 0.85D)
                        .build()
        );

'@
        $t = $t.Replace($marker, $insert + $marker)
    }
    return $t
}

Patch-File 'src/main/resources/assets/droingos_decor/lang/en_us.json' {
    param($t)
    $obj = $t | ConvertFrom-Json
    $obj | Add-Member -NotePropertyName 'item.droingos_decor.the_beast_skull' -NotePropertyValue "The Beast's Skull" -Force
    $obj | Add-Member -NotePropertyName 'block.droingos_decor.the_beast_skull' -NotePropertyValue "The Beast's Skull" -Force
    return ($obj | ConvertTo-Json -Depth 20)
}

